#include <stdio.h>
#include <math.h>
int isPrime(long long n) {
    if (n <= 1) return 0;
    if (n == 2) return 1;
    if (n % 2 == 0) return 0;
    for (long long i = 3; i * i <= n; i += 2) {
        if (n % i == 0) return 0;
    }
    return 1;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long A, B;
        scanf("%lld %lld", &A, &B);
        int flag = 1;
        for (long long i = 2; i * i <= B; i++) {
            if (B % i == 0) {
                if (isPrime(i) && A % i != 0) {
                    flag = 0;
                    break;
                }
                if (isPrime(B / i) && A % (B / i) != 0) {
                    flag = 0;
                    break;
                }
            }
        }
        if (B == 1) flag = 1;
        if (flag) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

